  "inlineSchema": "// 考研英语阅读刷题系统 - 数据库模型\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"../lib/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n}\n\n// 文章表\nmodel Article {\n  id         String   @id @default(cuid())\n  title      String // 文章标题\n  content    String // 文章正文\n  source     String? // 来源（如：2023年真题）\n  year       Int? // 年份\n  category   String? // 分类（经济/科技/文化等）\n  difficulty Int      @default(3) // 难度 1-5\n  wordCount  Int? // 字数\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n\n  questions       Question[]\n  practiceRecords PracticeRecord[]\n\n  @@map(\"articles\")\n}\n\n// 题目表\nmodel Question {\n  id            String  @id @default(cuid())\n  articleId     String\n  questionNum   Int // 题号 1-5\n  stem          String // 题干\n  questionType  String? // 题型（主旨/细节/推断/词义等）\n  analysis      String? // 解析\n  correctAnswer String // 正确答案 A/B/C/D\n\n  article       Article        @relation(fields: [articleId], references: [id], onDelete: Cascade)\n  options       Option[]\n  answerRecords AnswerRecord[]\n\n  @@unique([articleId, questionNum])\n  @@map(\"questions\")\n}\n\n// 选项表\nmodel Option {\n  id         String @id @default(cuid())\n  questionId String\n  optionKey  String // A/B/C/D\n  content    String // 选项内容\n\n  question Question @relation(fields: [questionId], references: [id], onDelete: Cascade)\n\n  @@unique([questionId, optionKey])\n  @@map(\"options\")\n}\n\n// 练习记录表（一次完整的练习）\nmodel PracticeRecord {\n  id             String    @id @default(cuid())\n  articleId      String\n  startTime      DateTime  @default(now())\n  endTime        DateTime?\n  duration       Int? // 用时（秒）\n  totalCorrect   Int       @default(0) // 正确数\n  totalQuestions Int       @default(0) // 总题数\n  isCompleted    Boolean   @default(false)\n\n  article       Article        @relation(fields: [articleId], references: [id], onDelete: Cascade)\n  answerRecords AnswerRecord[]\n\n  @@map(\"practice_records\")\n}\n\n// 答题记录表（单个题目的答案）\nmodel AnswerRecord {\n  id          String   @id @default(cuid())\n  practiceId  String\n  questionId  String\n  userAnswer  String? // 用户选择的答案 A/B/C/D\n  isCorrect   Boolean?\n  markedColor String? // 标记颜色\n  markedText  String? // 标记的文本片段\n  note        String? // 用户笔记\n  answeredAt  DateTime @default(now())\n\n  practice PracticeRecord @relation(fields: [practiceId], references: [id], onDelete: Cascade)\n  question Question       @relation(fields: [questionId], references: [id])\n\n  @@unique([practiceId, questionId])\n  @@map(\"answer_records\")\n}\n\n// AI问答记录表\nmodel AIChat {\n  id          String   @id @default(cuid())\n  questionId  String? // 关联的题目（可选）\n  articleId   String? // 关联的文章（可选）\n  userMessage String // 用户问题\n  aiResponse  String // AI回答\n  context     String? // 上下文（题目内容等）\n  createdAt   DateTime @default(now())\n\n  @@map(\"ai_chats\")\n}\n\n// 知识点表（RAG知识库）\nmodel Knowledge {\n  id        String   @id @default(cuid())\n  title     String // 知识点标题\n  content   String // 内容\n  category  String? // 分类（语法/词汇/技巧等）\n  tags      String? // 标签（JSON数组）\n  embedding String? // 向量嵌入（JSON数组）\n  source    String? // 来源（文章ID或手动添加）\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"knowledge\")\n}\n\n// 学习进度表\nmodel LearningProgress {\n  id                String   @id @default(cuid())\n  date              DateTime @default(now()) // 日期\n  articlesRead      Int      @default(0) // 阅读文章数\n  questionsAnswered Int      @default(0) // 答题数\n  correctCount      Int      @default(0) // 正确数\n  totalTime         Int      @default(0) // 总用时（秒）\n\n  @@unique([date])\n  @@map(\"learning_progress\")\n}\n\n// 错题本\nmodel WrongQuestion {\n  id          String   @id @default(cuid())\n  questionId  String\n  articleId   String\n  userAnswer  String // 错误答案\n  wrongCount  Int      @default(1) // 错误次数\n  lastWrongAt DateTime @default(now())\n  isMastered  Boolean  @default(false) // 是否已掌握\n  createdAt   DateTime @default(now())\n\n  @@unique([questionId])\n  @@map(\"wrong_questions\")\n}\n",
